tasks.command:
powershell -NoProfile -Command "
        $ErrorActionPreference = 'Stop';
        $limit = (Get-Date).AddSeconds(12);
        while (-not (Test-Path .\sim_ports.json)) { Start-Sleep -Milliseconds 200; if ((Get-Date) -gt $limit) { Write-Host 'Timeout waiting for sim_ports.json'; exit 1 } }
        $p = Get-Content .\sim_ports.json | ConvertFrom-Json;
        if (-not $p.rpc_port) { Write-Host 'rpc_port missing in sim_ports.json'; exit 1 }
        if (-not $p.uart_port) { Write-Host 'uart_port missing in sim_ports.json'; exit 1 }
        python .\simctl.py $($p.rpc_port) set_bg 255 32 32;
        python .\simctl.py $($p.rpc_port) scene 1;
        python .\simctl.py $($p.rpc_port) btn B press; Start-Sleep -Milliseconds 120; python .\simctl.py $($p.rpc_port) btn B release;
        $client = New-Object System.Net.Sockets.TcpClient; $client.Connect('127.0.0.1', [int]$p.uart_port); $w = New-Object System.IO.StreamWriter($client.GetStream()); $w.AutoFlush = $true; $w.WriteLine('set_bg 00ff00'); Start-Sleep -Milliseconds 100; $client.Close()
      "
